(function(){if(!!window.JCCatalogBrandSlider){return}window.JCCatalogBrandSlider=function(a){this.prevBtn;this.nextBtn;this.setButtons(a.hideDesktop,a.hideMobile);BXReady.showAjaxShadow("#sl_"+a.uniqId,"shadow_slider_"+a.uniqId);$("#sl_"+a.uniqId).slick({dots:a.dots,infinite:false,speed:a.speed,slidesToShow:a.XLG_CNT,slidesToScroll:1,prevArrow:this.prevBtn,nextArrow:this.nextBtn,lazyLoad:"ondemand",responsive:[{breakpoint:a.LG_BREAKPOINT,settings:{slidesToShow:a.LG_CNT,slidesToScroll:1}},{breakpoint:a.MD_BREAKPOINT,settings:{slidesToShow:a.MD_CNT,slidesToScroll:1}},{breakpoint:a.SM_BREAKPOINT,settings:{slidesToShow:a.SM_CNT,slidesToScroll:1}},{breakpoint:a.XS_BREAKPOINT,settings:{slidesToShow:a.XS_CNT,slidesToScroll:1}},]});$(".bxr-slick-section").css({height:"auto"});BXReady.closeAjaxShadow("shadow_slider_"+a.uniqId)};window.JCCatalogBrandSlider.prototype={isTouchDevice:function(){try{document.createEvent("TouchEvent");return true}catch(a){return false}},setButtons:function(a,b){isTouch=this.isTouchDevice();addClass=(!isTouch&&a||isTouch&&b)?" hidden-arrow":"";this.prevBtn='<button type="button" class="bxr-color-button slick-prev '+addClass+'"></button>';this.nextBtn='<button type="button" class="bxr-color-button slick-next '+addClass+'"></button>'}}})();